/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to a PDF file. LoadWWPContext.Call(&Context)
Do 'LoadGridState'
&Title = "Lista de Lançamento Pedidos"
//Report Template Source Header &AppName = "DVelop Software Solutions" &Phone = !"+1 550 8923" &Mail = !"info@mail.com" &Website = !"http://www.web.com" &AddressLine1 = !"French Boulevard 2859" &AddressLine2 = !"Downtown" &AddressLine3 = !"Paris, France" Print printTitle End Footer &PageInfo = "Page: " + &Page.ToString().Trim() &DateInfo = "Date: " + &Today.ToFormattedString() Print printFooter End
Do 'PrintFilters'
Do 'PrintColumnTitles'
Do 'PrintData'
Do 'PrintFooter'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'PrintFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not &PedVenCod.IsEmpty() print printBlockFilterPedVenCod EndIf If not &PedCod.IsEmpty() print printBlockFilterPedCod EndIf If not &PedCliCod.IsEmpty() print printBlockFilterPedCliCod EndIf If not &PedBlq.IsEmpty() &FilterPedBlqValueDescription = &PedBlq.EnumerationDescription()
print printBlockFilterPedBlq EndIf If not &FilCod.IsEmpty() print printBlockFilterFilCod EndIf If not &PedStsGer.IsEmpty() &FilterPedStsGerValueDescription = &PedStsGer.EnumerationDescription()
print printBlockFilterPedStsGer EndIf If not &PedDtaEms.IsEmpty() print printBlockFilterPedDtaEms EndIf If not &PedDtaEms_To.IsEmpty() &PedDtaEms_To_Description = format('%1 (%2)', "Emissão", "à") print printBlockFilterPedDtaEms_To EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'PEDENVCOD' &PedEnvCod1.FromString(&GridStateDynamicFilter.Value) If not &PedEnvCod1.IsEmpty() &PedEnvCod = &PedEnvCod1 print printBlockFilterPedEnvCod EndIf Case &DynamicFiltersSelector1 = !'PEDTRASAICOD' &PedTraSaiCod1.FromString(&GridStateDynamicFilter.Value) If not &PedTraSaiCod1.IsEmpty() &PedTraSaiCod = &PedTraSaiCod1 print printBlockFilterPedTraSaiCod EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'PEDENVCOD' &PedEnvCod2.FromString(&GridStateDynamicFilter.Value) If not &PedEnvCod2.IsEmpty() &PedEnvCod = &PedEnvCod2 print printBlockFilterPedEnvCod EndIf Case &DynamicFiltersSelector2 = !'PEDTRASAICOD' &PedTraSaiCod2.FromString(&GridStateDynamicFilter.Value) If not &PedTraSaiCod2.IsEmpty() &PedTraSaiCod = &PedTraSaiCod2 print printBlockFilterPedTraSaiCod EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'PEDENVCOD' &PedEnvCod3.FromString(&GridStateDynamicFilter.Value) If not &PedEnvCod3.IsEmpty() &PedEnvCod = &PedEnvCod3 print printBlockFilterPedEnvCod EndIf Case &DynamicFiltersSelector3 = !'PEDTRASAICOD' &PedTraSaiCod3.FromString(&GridStateDynamicFilter.Value) If not &PedTraSaiCod3.IsEmpty() &PedTraSaiCod = &PedTraSaiCod3 print printBlockFilterPedTraSaiCod EndIf EndCase EndIf EndIf EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
print printBlockBeforeGrid print printBlockLines_titles
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod FilCod (PedCod) when &OrderedBy = 1 order PedCod when &OrderedBy = 2 AND &OrderedDsc = False order (PedCod) when &OrderedBy = 2 AND &OrderedDsc = True order PedStsEnv when &OrderedBy = 3 AND &OrderedDsc = False order (PedStsEnv) when &OrderedBy = 3 AND &OrderedDsc = True order PedDtaEms when &OrderedBy = 4 AND &OrderedDsc = False order (PedDtaEms) when &OrderedBy = 4 AND &OrderedDsc = True order PedDtaDsp when &OrderedBy = 5 AND &OrderedDsc = False order (PedDtaDsp) when &OrderedBy = 5 AND &OrderedDsc = True order PedEnvCod when &OrderedBy = 6 AND &OrderedDsc = False order (PedEnvCod) when &OrderedBy = 6 AND &OrderedDsc = True
using DSwwAmostras(&PedVenCod, &PedCod, &PedCliCod, &PedBlq, &FilCod, &PedStsGer , &DynamicFiltersSelector1, &PedEnvCod1, &PedTraSaiCod1, &DynamicFiltersEnabled2, &DynamicFiltersSelector2, &PedEnvCod2 , &PedTraSaiCod2, &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &PedEnvCod3, &PedTraSaiCod3, &PedDtaEms , &PedDtaEms_To) &PedStsEnvDescription = PedStsEnv.EnumerationDescription() &PedNovCliRaz = iif(PedCliCodRaz_Nov.Length() > 30, Substr(PedCliCodRaz_Nov,1,30)+'...', PedCliCodRaz_Nov) &PedVenCodRaz = PedVenCodRaz
Do 'BeforePrintLine' print printBlockLines_data Do 'AfterPrintLine' EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"wwAmostrasGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"wwAmostrasGridState")) Else &GridState.FromXml(&Session.Get(!"wwAmostrasGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"PEDVENCOD" &PedVenCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDCOD" &PedCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDCLICOD" &PedCliCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDBLQ" &PedBlq.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"FILCOD" &FilCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDSTSGER" &PedStsGer.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDDTAEMS" &PedDtaEms.FromString(&GridStateFilterValue.Value) &PedDtaEms_To.FromString(&GridStateFilterValue.ValueTo) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
